import assert from "node:assert/strict";
import test from "node:test";

import { makeDefaultWorkspace, type WorkspaceState } from "../src/defaults.ts";
import { WorkspaceSession } from "../src/session.ts";

test("default factories do not share nested collections", () => {
  const first = makeDefaultWorkspace();
  const second = makeDefaultWorkspace();

  first.columns.push("priority");
  first.preferences.density = "compact";

  assert.deepEqual(second.columns, ["title", "status"]);
  assert.equal(second.preferences.density, "comfortable");
});

test("constructing a session does not transfer ownership from its caller", () => {
  const seed: WorkspaceState = {
    name: "Restored",
    columns: ["title"],
    preferences: { density: "comfortable", showHints: false },
  };
  const session = new WorkspaceSession(seed);
  session.addColumn("assignee");
  session.setDensity("compact");

  assert.deepEqual(seed, {
    name: "Restored",
    columns: ["title"],
    preferences: { density: "comfortable", showHints: false },
  });
});
